#include <bits/stdc++.h>
using namespace std;

const int N=1010,M=8e4+10,INF=1e9;

int n,m,t[15][65];
int head[N],ver[M],edge[M],val[M],nxt[M],tot=1;
int S,T,dis[N],f[N],pre[N],ans,q[M];
bool inq[N];

void add(int x,int y,int a,int b){
    ver[++tot]=y,edge[tot]=a,val[tot]=b,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,val[tot]=-b,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(inq,0,sizeof(inq));
    memset(dis,0x3f,sizeof(dis));
    int hh=1,tt=0;
    dis[S]=0,f[S]=INF;
    q[++tt]=S,inq[S]=1;
    while(hh<=tt){
        int x=q[hh++];
        //printf("%d %d %d\n",x,hh,tt);
        inq[x]=0;
        for(int i=head[x],y;i;i=nxt[i])
            if(edge[i] && dis[y=ver[i]]>dis[x]+val[i]){
                dis[y]=dis[x]+val[i];
                f[y]=min(f[x],edge[i]);
                pre[y]=i;
                /*
                if(y>N){
                	printf("%d %d\n",x,y);
                	return false;
				}
				*/
                if(!inq[y]) q[++tt]=y,inq[y]=1;
            }
    }
    return dis[T]<INF;
}

void Update(){
    int p=T,flow=f[T];
    ans+=f[T]*dis[T];
    while(p!=S){
        int i=pre[p];
        edge[i]-=flow,edge[i^1]+=flow;
        p=ver[i^1];
    }
}

int main(){
    scanf("%d%d",&m,&n);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            scanf("%d",&t[j][i]);
//    m=9,n=60;
//    for(int i=1;i<=n;i++)
//    	for(int j=1;j<=m;j++)
//    		t[j][i]=(i<<3)|(j<<4);
    S=n*m+n+1,T=n*m+n+2;
    for(int i=1;i<=m;i++)
        for(int j=1;j<=n;j++){
            int p=(i-1)*n+j;
            add(p,T,1,0);
            for(int k=1;k<=n;k++)
                add(n*m+k,p,1,t[i][k]*j);
        }
    for(int i=1;i<=n;i++)
        add(S,n*m+i,1,0);
    /*
    printf("%d\n",tot);
    for(int i=1;i<=n*m+n+2;i++){
    	for(int j=head[i];j;j=nxt[j])
    		printf("%d ",ver[j]);
    	puts("");
	}
	*/
    while(bfs())
        Update();
    printf("%.2lf",1.0*ans/n);
    return 0;
}
